<template><div><div class="stat-grid"><StatCard v-for="s in stats" :key="s.title" v-bind="s" /></div><div class="dashboard-grid"><el-card><template #header>今日调用趋势</template><div ref="trendRef" class="chart" /></el-card><el-card><template #header>资产类型分布</template><div ref="pieRef" class="chart" /></el-card><el-card><template #header>待办任务</template><el-timeline><el-timeline-item v-for="t in todos" :key="t" type="warning">{{t}}</el-timeline-item></el-timeline></el-card><el-card><template #header>最近风险提醒</template><el-alert v-for="r in risks" :key="r" :title="r" type="warning" show-icon class="mt" /></el-card></div></div></template>
<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'; import * as echarts from 'echarts'; import StatCard from '@/components/StatCard.vue'; import { assets, reviewTasks, rules, skills, tools } from '@/mock/data';
const trendRef=ref<HTMLElement>(); const pieRef=ref<HTMLElement>();
const stats=computed(()=>[{title:'数据资产总数',value:assets.length,desc:'较上周 +12%',trend:'up'},{title:'政策文件数',value:assets.filter(a=>a.type==='政策文件').length,desc:'已发布占比 67%'},{title:'知识切片数',value:2860,desc:'今日新增 46',trend:'up'},{title:'规则数',value:rules.length,desc:'待审核 1'},{title:'工具数',value:tools.length,desc:'可用率 98.6%',trend:'up'},{title:'技能数',value:skills.length,desc:'平均成功率 92%'},{title:'待审核数量',value:reviewTasks.length,desc:'需 24h 内处理',trend:'down'},{title:'低健康度资产数量',value:assets.filter(a=>['D','E'].includes(a.health)).length,desc:'需整改',trend:'down'},{title:'今日智脑调用次数',value:'12,486',desc:'峰值 10:30',trend:'up'},{title:'无依据回答次数',value:18,desc:'占比 0.14%',trend:'down'}]);
const todos=['2 条技能包待审核','1 个规则冲突需专家确认','3 个工具权限变更待发布']; const risks=['过期临时补贴政策仍有召回风险','居民阶梯电价说明存在疑似重复文件','高压新装材料清单编译失败'];
onMounted(()=>{ echarts.init(trendRef.value!).setOption({tooltip:{},xAxis:{type:'category',data:['08','10','12','14','16','18']},yAxis:{type:'value'},series:[{type:'line',smooth:true,areaStyle:{},data:[1200,2380,1800,3200,2800,1600],color:'#0f5ea8'}]}); echarts.init(pieRef.value!).setOption({tooltip:{},legend:{bottom:0},series:[{type:'pie',radius:['42%','68%'],data:[{name:'政策文件',value:42},{name:'知识切片',value:120},{name:'规则',value:26},{name:'工具',value:9},{name:'技能',value:16}]}]}); });
</script>
